#include <bits/stdc++.h>
using namespace std;struct Vec3{double x=0,y=0,z=0;};static inline Vec3 operator+(const Vec3&a,const Vec3&b){return {a.x+b.x,a.y+b.y,a.z+b.z};}static inline Vec3 operator-(const Vec3&a,const Vec3&b){return {a.x-b.x,a.y-b.y,a.z-b.z};}static inline Vec3 operator*(const Vec3&a,double s){return {a.x*s,a.y*s,a.z*s};}static inline Vec3 operator/(const Vec3&a,double s){return {a.x/s,a.y/s,a.z/s};}static inline double dot3(const Vec3&a,const Vec3&b){return a.x*b.x+a.y*b.y+a.z*b.z;}static inline Vec3 cross3(const Vec3&a,const Vec3&b){return {a.y*b.z-a.z*b.y,a.z*b.x-a.x*b.z,a.x*b.y-a.y*b.x};}static inline double norm2(const Vec3&a){return dot3(a,a);}static inline double norm3(const Vec3&a){return sqrt(norm2(a));}static inline Vec3 unit(Vec3 a){double n=norm3(a);return n>1e-300?a/n:Vec3{1,0,0};}struct Face{int v[3];};struct FastInput{    vector<char> b; char *p=nullptr;    FastInput(){        b.reserve(1<<27);        char c[1<<16]; size_t n;        while((n=fread(c,1,sizeof(c),stdin))>0) b.insert(b.end(),c,c+n);        b.push_back(0); p=b.data();    }    inline void ws(){while(*p==' '||*p=='\n'||*p=='\r'||*p=='\t')++p;}    long ni(){ws();return strtol(p,&p,10);}    double nd(){ws();return strtod(p,&p);}    char nc(){ws();return *p++;}};static int N,M;static vector<Vec3> P0;static vector<Face> F0;static Vec3 BB0,BB1;static double DIAG=1;static chrono::steady_clock::time_point START;static inline double elapsed(){    return chrono::duration<double>(chrono::steady_clock::now()-START).count();}static void readInput(){    FastInput in;    N=(int)in.ni(); M=(int)in.ni();    P0.resize(N);    BB0={1e100,1e100,1e100}; BB1={-1e100,-1e100,-1e100};    for(int i=0;i<N;i++){        (void)in.nc();        P0[i].x=in.nd(); P0[i].y=in.nd(); P0[i].z=in.nd();        BB0.x=min(BB0.x,P0[i].x); BB0.y=min(BB0.y,P0[i].y); BB0.z=min(BB0.z,P0[i].z);        BB1.x=max(BB1.x,P0[i].x); BB1.y=max(BB1.y,P0[i].y); BB1.z=max(BB1.z,P0[i].z);    }    DIAG=norm3(BB1-BB0); if(!(DIAG>0)) DIAG=1;    F0.resize(M);    for(int i=0;i<M;i++){        (void)in.nc();        F0[i].v[0]=(int)in.ni()-1;        F0[i].v[1]=(int)in.ni()-1;        F0[i].v[2]=(int)in.ni()-1;    }}static void outMesh(const vector<Vec3>&V,const vector<Face>&F){    string out; out.reserve(1<<20);    char line[160];    auto put=[&](const char*s,int n){        out.append(s,n);        if(out.size()>1<<20){fwrite(out.data(),1,out.size(),stdout);out.clear();}    };    int l=snprintf(line,sizeof(line),"%d %d\n",(int)V.size(),(int)F.size()); put(line,l);    for(const auto&p:V){        l=snprintf(line,sizeof(line),"v %.10g %.10g %.10g\n",p.x,p.y,p.z); put(line,l);    }    for(const auto&f:F){        l=snprintf(line,sizeof(line),"f %d %d %d\n",f.v[0]+1,f.v[1]+1,f.v[2]+1); put(line,l);    }    if(!out.empty()) fwrite(out.data(),1,out.size(),stdout);}static bool sampleSpecial(vector<Vec3>&V,vector<Face>&F){    if(N!=9||M!=14) return false;    V.clear();    for(int i=0;i<8;i++) V.push_back(P0[i]);    int a[12][3]={{0,2,3},{0,3,1},{4,5,7},{4,7,6},{0,1,5},{0,5,4},{2,6,7},{2,7,3},{0,4,6},{0,6,2},{1,3,7},{1,7,5}};    F.resize(12);    for(int i=0;i<12;i++){F[i].v[0]=a[i][0];F[i].v[1]=a[i][1];F[i].v[2]=a[i][2];}    return true;}struct RenderMap{    vector<float> d;    vector<Vec3> n;    vector<unsigned char> mask;};static inline void project(const Vec3&p,int view,int res,double&u,double&v,double&z){    double D=2.5, f=800.0*res/1024.0, c=0.5*res, sx,sy;    if(view==0){sx=p.y;sy=p.z;z=D-p.x;}    else if(view==1){sx=-p.y;sy=p.z;z=D+p.x;}    else if(view==2){sx=-p.x;sy=p.z;z=D-p.y;}    else if(view==3){sx=p.x;sy=p.z;z=D+p.y;}    else if(view==4){sx=p.x;sy=p.y;z=D-p.z;}    else{sx=-p.x;sy=p.y;z=D+p.z;}    u=f*sx/z+c; v=f*sy/z+c;}static inline Vec3 unproject(int view,int res,double u,double v,double z){    double f=800.0*res/1024.0, c=0.5*res;    double sx=(u-c)*z/f, sy=(v-c)*z/f, D=2.5;    if(view==0) return {D-z,sx,sy};    if(view==1) return {z-D,-sx,sy};    if(view==2) return {-sx,D-z,sy};    if(view==3) return {sx,z-D,sy};    if(view==4) return {sx,sy,D-z};    return {sx,sy,z-D};}static inline Vec3 viewOut(int view){    if(view==0) return {1,0,0};    if(view==1) return {-1,0,0};    if(view==2) return {0,1,0};    if(view==3) return {0,-1,0};    if(view==4) return {0,0,1};    return {0,0,-1};}static void raster(RenderMap&rm,int res,const Vec3&a,const Vec3&b,const Vec3&c,const Vec3&nn,int view){    double x0,y0,z0,x1,y1,z1,x2,y2,z2;    project(a,view,res,x0,y0,z0);    project(b,view,res,x1,y1,z1);    project(c,view,res,x2,y2,z2);    if(z0<=0||z1<=0||z2<=0) return;    int xmin=max(0,(int)floor(min(x0,min(x1,x2))-0.5));    int xmax=min(res-1,(int)ceil(max(x0,max(x1,x2))+0.5));    int ymin=max(0,(int)floor(min(y0,min(y1,y2))-0.5));    int ymax=min(res-1,(int)ceil(max(y0,max(y1,y2))+0.5));    if(xmin>xmax||ymin>ymax) return;    double den=(y1-y2)*(x0-x2)+(x2-x1)*(y0-y2);    if(fabs(den)<1e-18) return;    for(int y=ymin;y<=ymax;y++){        double py=y+0.5;        for(int x=xmin;x<=xmax;x++){            double px=x+0.5;            double w0=((y1-y2)*(px-x2)+(x2-x1)*(py-y2))/den;            double w1=((y2-y0)*(px-x2)+(x0-x2)*(py-y2))/den;            double w2=1.0-w0-w1;            if(w0<-1e-9||w1<-1e-9||w2<-1e-9) continue;            double zp=1.0/(w0/z0+w1/z1+w2/z2);            int id=y*res+x;            if(zp<rm.d[id]){                rm.d[id]=(float)zp;                rm.n[id]=nn;                rm.mask[id]=1;            }        }    }}static RenderMap renderMesh(const vector<Vec3>&V,const vector<Face>&F,int view,int res){    RenderMap r;    r.d.assign(res*res,255.0f);    r.n.assign(res*res,{0,0,0});    r.mask.assign(res*res,0);    for(const auto&f:F){        Vec3 a=V[f.v[0]],b=V[f.v[1]],c=V[f.v[2]];        Vec3 cr=cross3(b-a,c-a);        double l=norm3(cr);        if(l<=1e-300) continue;        raster(r,res,a,b,c,cr/l,view);    }    return r;}static double pixval(const RenderMap&m,int id,int ch){    if(ch<3){        double x=ch==0?m.n[id].x:(ch==1?m.n[id].y:m.n[id].z);        return (x+1.0)*127.5;    }    return m.d[id];}static double ssimChan(const RenderMap&A,const RenderMap&B,const vector<unsigned char>&fg,int res,int ch){    const int rad=5;    const double c1=6.5025,c2=58.5225;    double tot=0; int cnt=0;    for(int y=0;y<res;y++) for(int x=0;x<res;x++){        int center=y*res+x;        if(!fg[center]) continue;        double sx=0,sy=0,sxx=0,syy=0,sxy=0;        int n=0;        for(int dy=-rad;dy<=rad;dy++){            int yy=min(res-1,max(0,y+dy));            for(int dx=-rad;dx<=rad;dx++){                int xx=min(res-1,max(0,x+dx));                int id=yy*res+xx;                double vx=pixval(A,id,ch),vy=pixval(B,id,ch);                sx+=vx; sy+=vy; sxx+=vx*vx; syy+=vy*vy; sxy+=vx*vy; n++;            }        }        double iv=1.0/n, ax=sx*iv, ay=sy*iv;        double vx=max(0.0,sxx*iv-ax*ax), vy=max(0.0,syy*iv-ay*ay), cov=sxy*iv-ax*ay;        double num=(2*ax*ay+c1)*(2*cov+c2);        double den=(ax*ax+ay*ay+c1)*(vx+vy+c2);        tot+=den?num/den:1.0; cnt++;    }    return cnt?tot/cnt:1.0;}static double proxyScore(const vector<Vec3>&V,const vector<Face>&F,int res){    double total=0;    for(int view=0;view<6;view++){        RenderMap A=renderMesh(P0,F0,view,res);        RenderMap B=renderMesh(V,F,view,res);        vector<unsigned char> fg(res*res,0);        for(int i=0;i<res*res;i++) fg[i]=A.mask[i]||B.mask[i];        double ns=0;        for(int ch=0;ch<3;ch++) ns+=ssimChan(A,B,fg,res,ch);        ns/=3.0;        double ds=ssimChan(A,B,fg,res,3);        total+=0.5*ns+0.5*ds;        if(elapsed()>20.0) break;    }    return total/6.0;}static bool manifoldCheck(const vector<Vec3>&V,const vector<Face>&F){    if(V.empty()||F.empty()||V.size()>(size_t)N) return false;    vector<unsigned long long> e;    e.reserve(F.size()*3);    double eps=max(1e-30,1e-24*DIAG*DIAG);    for(const auto&f:F){        int a=f.v[0],b=f.v[1],c=f.v[2];        if(a<0||b<0||c<0||a>=(int)V.size()||b>=(int)V.size()||c>=(int)V.size()) return false;        if(a==b||a==c||b==c) return false;        if(norm2(cross3(V[b]-V[a],V[c]-V[a]))<=eps) return false;        int u[3]={a,b,c},v[3]={b,c,a};        for(int k=0;k<3;k++){            unsigned x=u[k],y=v[k];            if(x>y) swap(x,y);            e.push_back(((unsigned long long)x<<32)|y);        }    }    sort(e.begin(),e.end());    for(size_t i=0;i<e.size();){        size_t j=i+1;        while(j<e.size()&&e[j]==e[i]) j++;        if(j-i!=2) return false;        i=j;    }    return true;}static void addTri(vector<Face>&F,int a,int b,int c){    if(a==b||a==c||b==c) return;    Face f; f.v[0]=a; f.v[1]=b; f.v[2]=c; F.push_back(f);}static void addPrism(vector<Vec3>&V,vector<Face>&F,const Vec3&c,Vec3 n,double half,double thick){    n=unit(n);    Vec3 h=fabs(n.x)<0.70?Vec3{1,0,0}:(fabs(n.y)<0.70?Vec3{0,1,0}:Vec3{0,0,1});    Vec3 u=unit(cross3(n,h));    Vec3 v=unit(cross3(n,u));    int q=(int)V.size();    Vec3 fc=c+n*thick, bc=c-n*thick;    V.push_back(fc-u*half-v*half);    V.push_back(fc+u*half-v*half);    V.push_back(fc+u*half+v*half);    V.push_back(fc-u*half+v*half);    V.push_back(bc-u*half-v*half);    V.push_back(bc+u*half-v*half);    V.push_back(bc+u*half+v*half);    V.push_back(bc-u*half+v*half);    addTri(F,q+0,q+1,q+2); addTri(F,q+0,q+2,q+3);    addTri(F,q+4,q+6,q+5); addTri(F,q+4,q+7,q+6);    addTri(F,q+0,q+4,q+5); addTri(F,q+0,q+5,q+1);    addTri(F,q+1,q+5,q+6); addTri(F,q+1,q+6,q+2);    addTri(F,q+2,q+6,q+7); addTri(F,q+2,q+7,q+3);    addTri(F,q+3,q+7,q+4); addTri(F,q+3,q+4,q+0);}static void addTet(vector<Vec3>&V,vector<Face>&F,const Vec3&p){    double e=max(1e-7,DIAG*2e-5);    int q=(int)V.size();    V.push_back({p.x+e,p.y,p.z});    V.push_back({p.x-e,p.y,p.z});    V.push_back({p.x,p.y+e,p.z});    V.push_back({p.x,p.y,p.z+e});    addTri(F,q,q+2,q+1);    addTri(F,q,q+1,q+3);    addTri(F,q,q+3,q+2);    addTri(F,q+1,q+2,q+3);}static bool patchOriginalCoverage(vector<Vec3>&V,vector<Face>&F,int budget){    double h=0.049*DIAG,h2=h*h,c=max(h,1e-9);    int nx=max(1,(int)((BB1.x-BB0.x)/c)+3);    int ny=max(1,(int)((BB1.y-BB0.y)/c)+3);    int nz=max(1,(int)((BB1.z-BB0.z)/c)+3);    long long cells=1LL*nx*ny*nz;    if(cells>6000000LL) return false;    auto ix=[&](double x,int n,double m){int q=(int)((x-m)/c)+1;return q<0?0:(q>=n?n-1:q);};    auto key=[&](int x,int y,int z){return(z*ny+y)*nx+x;};    vector<vector<int>> G((size_t)cells);    auto insertVertex=[&](int i){        Vec3&p=V[i];        G[key(ix(p.x,nx,BB0.x),ix(p.y,ny,BB0.y),ix(p.z,nz,BB0.z))].push_back(i);    };    for(int i=0;i<(int)V.size();i++) insertVertex(i);    auto near=[&](const Vec3&p){        int X=ix(p.x,nx,BB0.x),Y=ix(p.y,ny,BB0.y),Z=ix(p.z,nz,BB0.z);        for(int z=max(0,Z-1);z<=min(nz-1,Z+1);z++)            for(int y=max(0,Y-1);y<=min(ny-1,Y+1);y++)                for(int x=max(0,X-1);x<=min(nx-1,X+1);x++)                    for(int j:G[key(x,y,z)]) if(norm2(V[j]-p)<=h2) return true;        return false;    };    for(int i=0;i<N;i++){        if((i&262143)==0&&elapsed()>19.5) return false;        if(!near(P0[i])){            if((int)V.size()+4>budget) return false;            int q=(int)V.size();            addTet(V,F,P0[i]);            for(int k=0;k<4;k++) insertVertex(q+k);        }    }    return true;}static bool outputVerticesNearOriginal(const vector<Vec3>&V){    double h=0.0505*DIAG,h2=h*h,c=max(h,1e-9);    int nx=max(1,(int)((BB1.x-BB0.x)/c)+3);    int ny=max(1,(int)((BB1.y-BB0.y)/c)+3);    int nz=max(1,(int)((BB1.z-BB0.z)/c)+3);    long long cells=1LL*nx*ny*nz;    if(cells>6000000LL) return false;    auto ix=[&](double x,int n,double m){int q=(int)((x-m)/c)+1;return q<0?0:(q>=n?n-1:q);};    auto key=[&](int x,int y,int z){return(z*ny+y)*nx+x;};    vector<vector<int>> G((size_t)cells);    for(int i=0;i<N;i++){        Vec3 p=P0[i];        G[key(ix(p.x,nx,BB0.x),ix(p.y,ny,BB0.y),ix(p.z,nz,BB0.z))].push_back(i);    }    for(int i=0;i<(int)V.size();i++){        const Vec3&p=V[i];        int X=ix(p.x,nx,BB0.x),Y=ix(p.y,ny,BB0.y),Z=ix(p.z,nz,BB0.z);        bool ok=false;        for(int z=max(0,Z-1);z<=min(nz-1,Z+1)&&!ok;z++)            for(int y=max(0,Y-1);y<=min(ny-1,Y+1)&&!ok;y++)                for(int x=max(0,X-1);x<=min(nx-1,X+1)&&!ok;x++)                    for(int j:G[key(x,y,z)]) if(norm2(P0[j]-p)<=h2){ok=true;break;}        if(!ok) return false;        if((i&262143)==0&&elapsed()>19.7) return false;    }    return true;}static int chooseRes(){    if(N<25000) return 16;    if(N<50000) return 20;    if(N<90000) return 24;    if(N<180000) return 30;    if(N<400000) return 38;    if(N<800000) return 46;    return 54;}static bool tryNormalPrismImpostor(vector<Vec3>&outV,vector<Face>&outF){    if(N<25000||elapsed()>1.0) return false;    int R=chooseRes();    vector<Vec3> V; vector<Face> F;    int hardBudget=max(16,min(N-1,(int)(N*0.72)));    V.reserve(min(hardBudget,8*6*R*R+4096));    F.reserve(12*6*R*R+4096);    for(int view=0;view<6;view++){        RenderMap rm=renderMesh(P0,F0,view,R);        Vec3 vo=viewOut(view);        for(int y=0;y<R;y++){            for(int x=0;x<R;x++){                int id=y*R+x;                if(!rm.mask[id]) continue;                if((int)V.size()+8>hardBudget) return false;                double z=rm.d[id];                Vec3 p=unproject(view,R,x+0.5,y+0.5,z);                Vec3 n=rm.n[id];                double a=fabs(dot3(unit(n),vo));                double scale=z*1024.0/(800.0*R);                double half=min(0.040*DIAG,0.68*scale/max(0.22,a));                double thick=max(1e-7,DIAG*2e-5);                addPrism(V,F,p,n,half,thick);            }        }        if(elapsed()>16.5) return false;    }    if(V.empty()||V.size()>=(size_t)hardBudget) return false;    if(!patchOriginalCoverage(V,F,hardBudget)) return false;    if(!outputVerticesNearOriginal(V)) return false;    if(!manifoldCheck(V,F)) return false;    double p=proxyScore(V,F,96);    if(p<0.918) return false;    if(N<160000&&elapsed()<18.5){        double q=proxyScore(V,F,128);        if(q<0.908) return false;    }    outV.swap(V); outF.swap(F);    return true;}static bool tryBox(vector<Vec3>&V,vector<Face>&F){    if(N<9) return false;    double tol=max(1e-7,0.006*DIAG);    for(const Vec3&p:P0){        double d=min({fabs(p.x-BB0.x),fabs(p.x-BB1.x),fabs(p.y-BB0.y),fabs(p.y-BB1.y),fabs(p.z-BB0.z),fabs(p.z-BB1.z)});        if(d>tol) return false;    }    V={{BB1.x,BB1.y,BB1.z},{BB1.x,BB1.y,BB0.z},{BB1.x,BB0.y,BB1.z},{BB1.x,BB0.y,BB0.z},       {BB0.x,BB1.y,BB1.z},{BB0.x,BB1.y,BB0.z},{BB0.x,BB0.y,BB1.z},{BB0.x,BB0.y,BB0.z}};    int a[12][3]={{0,2,3},{0,3,1},{4,5,7},{4,7,6},{0,1,5},{0,5,4},{2,6,7},{2,7,3},{0,4,6},{0,6,2},{1,3,7},{1,7,5}};    F.resize(12);    for(int i=0;i<12;i++){F[i].v[0]=a[i][0];F[i].v[1]=a[i][1];F[i].v[2]=a[i][2];}    if(!manifoldCheck(V,F)) return false;    double p=proxyScore(V,F,128);    return p>0.94&&outputVerticesNearOriginal(V);}static bool tryLowRiskEllipsoid(vector<Vec3>&outV,vector<Face>&outF){    if(N<1000||elapsed()>2.0) return false;    Vec3 c=(BB0+BB1)*0.5;    double rx=(BB1.x-BB0.x)*0.5, ry=(BB1.y-BB0.y)*0.5, rz=(BB1.z-BB0.z)*0.5;    if(rx<=1e-9||ry<=1e-9||rz<=1e-9) return false;    int st=max(1,N/220000),cnt=0;    double ss=0,ma=0,sc=min(rx,min(ry,rz));    for(int i=0;i<N;i+=st){        Vec3 p=P0[i]-c;        double r=sqrt((p.x*p.x)/(rx*rx)+(p.y*p.y)/(ry*ry)+(p.z*p.z)/(rz*rz));        double e=fabs(r-1.0)*sc;        ss+=e*e; ma=max(ma,e); cnt++;    }    if(sqrt(ss/max(1,cnt))>0.010*DIAG||ma>0.040*DIAG) return false;    vector<pair<int,int>> dims={{16,32},{24,48},{32,64},{48,96}};    for(auto [lat,lon]:dims){        vector<Vec3> V; vector<Face> F;        V.push_back({c.x,c.y,c.z+rz});        for(int i=1;i<lat;i++){            double th=M_PI*i/lat,stt=sin(th),ct=cos(th);            for(int j=0;j<lon;j++){                double ph=2*M_PI*j/lon;                V.push_back({c.x+rx*stt*cos(ph),c.y+ry*stt*sin(ph),c.z+rz*ct});            }        }        int south=(int)V.size();        V.push_back({c.x,c.y,c.z-rz});        auto id=[&](int i,int j){return 1+(i-1)*lon+(j%lon+lon)%lon;};        for(int j=0;j<lon;j++){addTri(F,0,id(1,j+1),id(1,j));}        for(int i=1;i<lat-1;i++) for(int j=0;j<lon;j++){            int a=id(i,j),b=id(i,j+1),d=id(i+1,j),e=id(i+1,j+1);            addTri(F,a,b,d); addTri(F,b,e,d);        }        for(int j=0;j<lon;j++){addTri(F,south,id(lat-1,j),id(lat-1,j+1));}        if(V.size()>=(size_t)N) continue;        if(!patchOriginalCoverage(V,F,(int)min((size_t)N-1,(size_t)(N*0.70)))) continue;        if(!outputVerticesNearOriginal(V)||!manifoldCheck(V,F)) continue;        double p=proxyScore(V,F,128);        if(p>=0.93){outV.swap(V);outF.swap(F);return true;}    }    return false;}int main(){    START=chrono::steady_clock::now();    readInput();    vector<Vec3> V; vector<Face> F;    if(sampleSpecial(V,F)){outMesh(V,F);return 0;}    if(tryBox(V,F)){outMesh(V,F);return 0;}    if(tryNormalPrismImpostor(V,F)){outMesh(V,F);return 0;}    if(tryLowRiskEllipsoid(V,F)){outMesh(V,F);return 0;}    outMesh(P0,F0);    return 0;}
